<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        body { font-family: sans-serif; max-width: 800px; margin: 20px auto; padding: 0 20px; line-height: 1.5; }
        section { margin-bottom: 30px; padding: 15px; border: 1px solid #ccc; border-radius: 8px; }
        h2 { margin-top: 0; }
        .form-group { margin-bottom: 10px; }
        label { display: block; font-weight: bold; }
        input, select { padding: 8px; width: 100%; box-sizing: border-box; margin-top: 4px; }
        #add-expense { padding: 10px 20px; cursor: pointer; background: #28a745; color: white; border: none; border-radius: 4px; font-weight: bold; }
        #form-error { color: red; margin-bottom: 10px; height: 1.2em; font-size: 0.9em; }
        .filters { display: flex; gap: 15px; flex-wrap: wrap; align-items: flex-end; }
        .filter-item { flex: 1; min-width: 150px; }
        .summary-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 10px; margin-bottom: 15px; }
        .cat-total { padding: 10px; background: #f4f4f4; border: 1px solid #ddd; border-radius: 4px; text-align: center; font-size: 0.9em; }
        .cat-total strong { display: block; text-transform: capitalize; }
        #total-container { font-size: 1.2em; font-weight: bold; margin-bottom: 15px; text-align: right; }
        table { width: 100%; border-collapse: collapse; }
        th, td { text-align: left; padding: 10px; border-bottom: 1px solid #eee; }
        .expense { transition: background 0.2s; }
        .exp-del { color: white; background: #dc3545; border: none; padding: 5px 10px; cursor: pointer; border-radius: 3px; }
    </style>
</head>
<body>

    <h1>Expense Tracker</h1>

    <section id="entry">
        <h2>Add Expense</h2>
        <div id="form-error"></div>
        <div class="form-group">
            <label for="amount">Amount</label>
            <input type="number" id="amount" step="0.01" placeholder="0.00">
        </div>
        <div class="form-group">
            <label for="category">Category</label>
            <select id="category">
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>
        <div class="form-group">
            <label for="date">Date</label>
            <input type="date" id="date">
        </div>
        <div class="form-group">
            <label for="note">Note (Optional)</label>
            <input type="text" id="note" placeholder="What was this for?">
        </div>
        <button id="add-expense">Add Expense</button>
    </section>

    <section id="filters-section">
        <h2>Filters</h2>
        <div class="filters">
            <div class="filter-item">
                <label for="filter-category">Category</label>
                <select id="filter-category">
                    <option value="all">All</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div class="filter-item">
                <label for="filter-from">From Date</label>
                <input type="date" id="filter-from">
            </div>
            <div class="filter-item">
                <label for="filter-to">To Date</label>
                <input type="date" id="filter-to">
            </div>
        </div>
    </section>

    <section id="display">
        <h2>Summary & History</h2>
        <div class="summary-grid" id="category-summaries">
            <!-- Generated by JS -->
        </div>
        <div id="total-container">Total: $<span id="total">0.00</span></div>
        <table>
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Category</th>
                    <th>Amount</th>
                    <th>Note</th>
                    <th>Action</th>
                </tr>
            </thead>
            <tbody id="expense-list"></tbody>
        </table>
    </section>

    <script>
        const categories = ['groceries', 'transport', 'bills', 'fun'];
        let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

        // DOM Elements
        const amountInput = document.getElementById('amount');
        const categoryInput = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const addBtn = document.getElementById('add-expense');
        const formError = document.getElementById('form-error');

        const filterCat = document.getElementById('filter-category');
        const filterFrom = document.getElementById('filter-from');
        const filterTo = document.getElementById('filter-to');

        const totalEl = document.getElementById('total');
        const listEl = document.getElementById('expense-list');
        const summaryContainer = document.getElementById('category-summaries');

        // Initialize category summaries in HTML
        function initSummary() {
            summaryContainer.innerHTML = '';
            categories.forEach(cat => {
                const div = document.createElement('div');
                div.className = 'cat-total';
                div.setAttribute('data-cat', cat);
                div.innerHTML = `<strong>${cat}</strong> $<span>0.00</span>`;
                summaryContainer.appendChild(div);
            });
        }

        function save() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
            render();
        }

        function render() {
            const catFilter = filterCat.value;
            const fromDate = filterFrom.value;
            const toDate = filterTo.value;

            // Filter and Sort (Newest first)
            const filtered = expenses.filter(exp => {
                const matchCat = (catFilter === 'all' || exp.category === catFilter);
                const matchFrom = (!fromDate || exp.date >= fromDate);
                const matchTo = (!toDate || exp.date <= toDate);
                return matchCat && matchFrom && matchTo;
            }).sort((a, b) => new Date(b.date) - new Date(a.date));

            // Render List
            listEl.innerHTML = '';
            let grandTotal = 0;
            const catTotals = {};
            categories.forEach(c => catTotals[c] = 0);

            filtered.forEach(exp => {
                grandTotal += exp.amount;
                catTotals[exp.category] += exp.amount;

                const row = document.createElement('tr');
                row.className = 'expense';
                row.innerHTML = `
                    <td>${exp.date}</td>
                    <td>${exp.category}</td>
                    <td>${exp.amount.toFixed(2)}</td>
                    <td>${exp.note || ''}</td>
                    <td><button class="exp-del" data-id="${exp.id}">Delete</button></td>
                `;
                listEl.appendChild(row);
            });

            // Update Total
            totalEl.textContent = grandTotal.toFixed(2);

            // Update Category Totals
            categories.forEach(cat => {
                const el = document.querySelector(`.cat-total[data-cat="${cat}"] span`);
                if (el) el.textContent = catTotals[cat].toFixed(2);
            });

            // Attach delete events
            document.querySelectorAll('.exp-del').forEach(btn => {
                btn.onclick = () => {
                    const id = parseInt(btn.getAttribute('data-id'));
                    expenses = expenses.filter(e => e.id !== id);
                    save();
                };
            });
        }

        addBtn.onclick = () => {
            const amount = parseFloat(amountInput.value);
            const category = categoryInput.value;
            const date = dateInput.value;
            const note = noteInput.value;

            // Validation
            if (isNaN(amount) || amount <= 0) {
                formError.textContent = "Please enter a valid positive number for amount.";
                return;
            }
            if (!date) {
                formError.textContent = "Please select a date.";
                return;
            }

            // Success
            formError.textContent = "";
            expenses.push({
                id: Date.now(),
                amount,
                category,
                date,
                note
            });

            amountInput.value = ''; // Reset amount field
            save();
        };

        // Filter listeners
        filterCat.onchange = render;
        filterFrom.oninput = render;
        filterTo.oninput = render;

        // Init
        initSummary();
        render();
    </script>
</body>
</html>
